import React, { useState, useEffect } from 'react';
import { getRecords, clearRecords, getTotalEcoPoints, getTotalGreenCredits, getTotalCO2, GREEN_CREDIT_MULTIPLIER, ECO_POINTS } from '../services/store';
import { calcImpact, calcEcoScore, generateInsights, IMPACT } from '../services/api';
import WastePieChart from '../components/WastePieChart';
import DailyBarChart from '../components/DailyBarChart';
import ImpactPanel from '../components/ImpactPanel';
import './Dashboard.css';

export default function Dashboard() {
  const [records, setRecords] = useState([]);
  const [showClearConfirm, setShowClearConfirm] = useState(false);

  useEffect(() => { setRecords(getRecords()); }, []);

  const total        = records.length;
  const recyclable   = records.filter(r => r.category === 'Recyclable').length;
  const biodegradable= records.filter(r => r.category === 'Biodegradable').length;
  const hazardous    = records.filter(r => r.category === 'Hazardous').length;
  const impact       = calcImpact(records);
  const ecoScore     = calcEcoScore(records);
  const insights       = generateInsights(records);
  const totalEcoPoints   = getTotalEcoPoints(records);
  const totalGreenCredits= getTotalGreenCredits(records);
  const totalCO2         = getTotalCO2(records);
  const hazardAlert      = hazardous >= 3;  // threshold: 3+ hazardous items
  const commScans      = (total * 180 + 8420).toLocaleString();
  const commCO2        = (impact.co2 * 180 + 1247).toFixed(1) + ' kg';
  const commPts        = (totalEcoPoints * 180 + 44800).toLocaleString();

  const pct = n => total ? Math.round((n / total) * 100) : 0;

  function handleClear() {
    clearRecords();
    setRecords([]);
    setShowClearConfirm(false);
  }

  // Score colour
  const scoreColor = ecoScore >= 70 ? 'var(--brand-teal)' : ecoScore >= 40 ? '#f59e0b' : '#ef4444';
  const scoreLabel = ecoScore >= 70 ? 'Excellent' : ecoScore >= 40 ? 'Good Progress' : 'Needs Improvement';

  return (
    <div className="page-content dashboard-page">
      {/* Header */}
      <div className="dash-header">
        <div>
          <h1 className="dash-title">Analytics</h1>
          <p className="dash-sub">VERDANT · Sustainability Overview</p>
        </div>
        {total > 0 && (
          <button className="clear-btn" onClick={() => setShowClearConfirm(true)}
            title="Clear all data">✕</button>
        )}
      </div>

      {total === 0 ? (
        <EmptyState />
      ) : (
        <>
          {/* ⚠️ Hazard Alert */}
          {hazardAlert && (
            <div className="hazard-alert">
              <span className="hazard-alert-icon">⚠️</span>
              <div>
                <p className="hazard-alert-title">Hazardous Waste Alert</p>
                <p className="hazard-alert-msg">{hazardous} hazardous items detected. Ensure proper disposal at a certified collection point. Do NOT mix with regular waste.</p>
              </div>
            </div>
          )}

          {/* ── Summary Cards ── */}
          <section className="dash-section">
            <h2 className="dash-section-title">Summary</h2>
            <div className="metrics-grid">
              <MetricCard icon="📦" value={total}        label="Total Scanned" color="var(--brand-teal)" bg="rgba(0,200,150,.10)" />
              <MetricCard icon="♻️" value={pct(recyclable) + '%'} label="Recyclable"  color="#60a5fa" bg="rgba(96,165,250,.10)" />
              <MetricCard icon="🌿" value={pct(biodegradable) + '%'} label="Biodegradable" color="#4ade80" bg="rgba(74,222,128,.10)" />
              <MetricCard icon="⚠️" value={hazardous}    label="Hazardous"     color="#f87171" bg="rgba(248,113,113,.10)" />
              <MetricCard icon="🌫️" value={totalCO2.toFixed(2) + ' kg'} label="Total CO₂ Saved" color="var(--brand-teal)" bg="rgba(0,200,150,.08)" wide />
            </div>
          </section>

          {/* ── Green Credits ── */}
          <section className="dash-section">
            <h2 className="dash-section-title">Green Credits</h2>
            <div className="green-credits-card">
              <div className="gc-header">
                <span className="gc-leaf">🟢</span>
                <div>
                  <p className="gc-total-num">{totalGreenCredits}</p>
                  <p className="gc-total-label">Total Green Credits Earned</p>
                </div>
              </div>
              <p className="gc-formula">Formula: <code>Credits = CO₂_saved × category_multiplier × 10</code></p>
              <div className="gc-breakdown">
                <GcRow icon="♻️" label="Recyclable" mult={GREEN_CREDIT_MULTIPLIER.Recyclable} count={recyclable} color="#60a5fa" records={records} />
                <GcRow icon="🌿" label="Biodegradable" mult={GREEN_CREDIT_MULTIPLIER.Biodegradable} count={biodegradable} color="#4ade80" records={records} />
                <GcRow icon="⚠️" label="Hazardous" mult={GREEN_CREDIT_MULTIPLIER.Hazardous} count={hazardous} color="#f87171" records={records} />
              </div>
              <div className="gc-redeem">
                <span>🎟️</span>
                <p>Redeemable for: transit discounts · campus incentives · eco-store rewards</p>
              </div>
            </div>
          </section>

          {/* ── Eco Score ── */}
          <section className="dash-section">
            <h2 className="dash-section-title">Sustainability Score</h2>
            <div className="eco-score-card">
              <div className="score-ring-wrap">
                <svg className="score-ring" viewBox="0 0 120 120">
                  <circle cx="60" cy="60" r="50" fill="none" stroke="rgba(255,255,255,.08)" strokeWidth="10" />
                  <circle
                    cx="60" cy="60" r="50" fill="none"
                    stroke={scoreColor} strokeWidth="10"
                    strokeLinecap="round"
                    strokeDasharray={`${(ecoScore / 100) * 314} 314`}
                    transform="rotate(-90 60 60)"
                    style={{ transition: 'stroke-dasharray 1s ease' }}
                  />
                  <text x="60" y="58" textAnchor="middle" fontSize="22" fontWeight="800" fill={scoreColor}>{ecoScore}</text>
                  <text x="60" y="76" textAnchor="middle" fontSize="10" fill="rgba(255,255,255,.35)">/100</text>
                </svg>
              </div>
              <div className="score-info">
                <p className="score-label-text" style={{ color: scoreColor }}>{scoreLabel}</p>
                <p className="score-detail">Based on recycling rate, disposal accuracy, and hazardous compliance.</p>
                <div className="score-bars">
                  <ScoreBar label="Recycling Rate" value={pct(recyclable)} color="#60a5fa" />
                  <ScoreBar label="Correct Disposal" value={pct(recyclable + biodegradable)} color="var(--brand-teal)" />
                  <ScoreBar label="Hazardous Control" value={hazardous === 0 ? 100 : Math.max(0, 100 - Math.round((hazardous / total) * 200))} color="#f87171" />
                </div>
              </div>
            </div>
          </section>

          {/* ── Charts ── */}
          <section className="dash-section">
            <h2 className="dash-section-title">Waste Distribution</h2>
            <div className="chart-card">
              <WastePieChart records={records} />
            </div>
          </section>

          <section className="dash-section">
            <h2 className="dash-section-title">Daily Trends (Last 7 Days)</h2>
            <div className="chart-card">
              <DailyBarChart records={records} />
            </div>
          </section>

          {/* ── Environmental Impact ── */}
          <ImpactPanel
            co2={impact.co2}
            energy={impact.energy}
            landfill={impact.landfill}
            trees={impact.trees}
          />

          {/* ── AI Insights ── */}
          <section className="dash-section">
            <h2 className="dash-section-title">AI Insights</h2>
            <div className="insights-card">
              {insights.map((ins, i) => (
                <div className="insight-item" key={i}>
                  <span className="insight-dot" />
                  <p className="insight-text">{ins}</p>
                </div>
              ))}
            </div>
          </section>

          {/* ── Recent Activity ── */}
          <section className="dash-section">
            <h2 className="dash-section-title">Recent Activity</h2>
            <div className="activity-feed">
              {records.slice(0, 20).map(r => (
                <ActivityItem key={r.id} record={r} />
              ))}
              {records.length > 20 && (
                <p className="activity-more">+ {records.length - 20} more items</p>
              )}
            </div>
          </section>

          {/* ── Community Impact ── */}
          <section className="dash-section">
            <h2 className="dash-section-title">Community Impact</h2>
            <div className="community-card">
              <CommStat icon="👥" value="2,341" label="Active participants" />
              <CommStat icon="🌍" value={commCO2} label="Community CO₂ prevented" />
              <CommStat icon="♻️" value={commScans} label="Items correctly sorted" />
              <CommStat icon="🌱" value={commPts} label="Community eco-points" />
            </div>
          </section>

          {/* ── Top Contributors ── */}
          <section className="dash-section" style={{ paddingBottom: 24 }}>
            <h2 className="dash-section-title">Top Contributors</h2>
            <div className="leaderboard-card">
              {buildLeaderboard(totalEcoPoints).map(e => (
                <LeaderboardRow key={e.name} {...e} />
              ))}
            </div>
          </section>
        </>
      )}

      {/* Clear confirm */}
      {showClearConfirm && (
        <div className="modal-overlay">
          <div className="modal-card">
            <h3>Clear All Data?</h3>
            <p>This will permanently delete all scan history and reset your dashboard.</p>
            <div className="modal-actions">
              <button className="btn btn-outline" onClick={() => setShowClearConfirm(false)}>Cancel</button>
              <button className="btn btn-danger" onClick={handleClear}>Clear All</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

function MetricCard({ icon, value, label, color, bg, wide }) {
  return (
    <div className={`metric-card${wide ? ' metric-wide' : ''}`}>
      <div className="metric-icon-wrap" style={{ background: bg || 'rgba(0,200,150,.10)' }}>
        <span className="metric-icon">{icon}</span>
      </div>
      <div>
        <span className="metric-value" style={{ color }}>{value}</span>
        <p className="metric-label">{label}</p>
      </div>
    </div>
  );
}

function ScoreBar({ label, value, color }) {
  return (
    <div className="score-bar-row">
      <span className="score-bar-label">{label}</span>
      <div className="score-bar-track">
        <div className="score-bar-fill" style={{ width: value + '%', background: color }} />
      </div>
      <span className="score-bar-pct">{value}%</span>
    </div>
  );
}

function ActivityItem({ record }) {
  const imp = IMPACT[record.category] || {};
  const dt  = new Date(record.timestamp);
  const timeStr = dt.toLocaleDateString('en-IN', { day: '2-digit', month: 'short' })
    + ' · ' + dt.toLocaleTimeString('en-IN', { hour: '2-digit', minute: '2-digit' });

  return (
    <div className="activity-item" style={{ borderLeftColor: imp.color }}>
      <span className="activity-icon">{imp.icon}</span>
      <div className="activity-info">
        <div className="activity-top-row">
          <p className="activity-category" style={{ color: imp.color }}>
            {record.category}{record.object_detected ? ` · ${record.object_detected}` : ''}
          </p>
          {record.green_credits ? (
            <span className="activity-gc-badge">🟢 {record.green_credits} credits</span>
          ) : null}
        </div>
        {record.co2_saved > 0 && (
          <p className="activity-co2">🌫️ {record.co2_saved.toFixed(2)} kg CO₂ prevented</p>
        )}
        <p className="activity-time">{timeStr}</p>
      </div>
    </div>
  );
}

function GcRow({ icon, label, mult, count, color, records }) {
  const total = records
    .filter(r => r.category === label)
    .reduce((sum, r) => sum + (r.green_credits || 0), 0);
  return (
    <div className="ep-row">
      <div className="ep-row-left">
        <span className="ep-row-icon">{icon}</span>
        <div className="ep-row-info">
          <p className="ep-row-label">{label}</p>
          <p className="ep-row-count">×{mult} multiplier · {count} item{count !== 1 ? 's' : ''}</p>
        </div>
      </div>
      <span className="ep-row-pts" style={{ color }}>{total} <span style={{fontSize:'.7rem',fontWeight:500,color:'var(--text-muted)'}}>credits</span></span>
    </div>
  );
}

function EpRow({ icon, label, count, pts, color }) {
  return (
    <div className="ep-row">
      <div className="ep-row-left">
        <span className="ep-row-icon">{icon}</span>
        <div className="ep-row-info">
          <p className="ep-row-label">{label}</p>
          <p className="ep-row-count">{count} item{count !== 1 ? 's' : ''}</p>
        </div>
      </div>
      <span className="ep-row-pts" style={{ color }}>{pts} pts</span>
    </div>
  );
}

function CommStat({ icon, value, label }) {
  return (
    <div className="comm-stat">
      <span className="comm-stat-icon">{icon}</span>
      <p className="comm-stat-value">{value}</p>
      <p className="comm-stat-label">{label}</p>
    </div>
  );
}

function LeaderboardRow({ rank, name, pts, isUser }) {
  const medal = rank === 1 ? '🥇' : rank === 2 ? '🥈' : rank === 3 ? '🥉' : rank;
  return (
    <div className={`lb-row${isUser ? ' lb-you' : ''}`}>
      <span className="lb-rank">{medal}</span>
      <span className="lb-name">{name}{isUser ? ' (You)' : ''}</span>
      <span className="lb-pts">{pts}<span className="lb-pts-unit"> pts</span></span>
    </div>
  );
}

const MOCK_CONTRIBUTORS = [
  { name: 'Priya S.',   pts: 342 },
  { name: 'Rahul M.',   pts: 287 },
  { name: 'Ananya K.',  pts: 251 },
  { name: 'Vikram T.',  pts: 198 },
  { name: 'Meera P.',   pts: 167 },
];

function buildLeaderboard(userPts) {
  return [...MOCK_CONTRIBUTORS, { name: 'You', pts: userPts, isUser: true }]
    .sort((a, b) => b.pts - a.pts)
    .map((e, i) => ({ ...e, rank: i + 1 }));
}

function EmptyState() {
  return (
    <div className="empty-state">
      <div className="empty-icon-wrap">
        <span className="empty-icon">📊</span>
      </div>
      <h3>No Scans Yet</h3>
      <p>Head to the Scan tab and classify your first waste item — your sustainability data will appear here.</p>
    </div>
  );
}
